#include <stdio.h>
#include <stdlib.h>

int findFirst(int *arr, int n, int key) {
    int left = 0, right = n - 1, first = -1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] < key) left = mid + 1;
        else if (arr[mid] > key) right = mid - 1;
        else { first = mid; right = mid - 1; }
    }
    return first;
}

int findLast(int *arr, int n, int key) {
    int left = 0, right = n - 1, last = -1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] < key) left = mid + 1;
        else if (arr[mid] > key) right = mid - 1;
        else { last = mid; left = mid + 1; }
    }
    return last;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, key; scanf("%d %d", &n, &key);
        int *arr = NULL;
        if (n > 0) {
            arr = (int*)malloc(n * sizeof(int));
            for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        }
        int first = findFirst(arr, n, key);
        int last  = findLast(arr, n, key);
        printf("%d %d\n", first, last);
        free(arr);
    }
    return 0;
}

