import java.io.*;
import java.util.*;

public class Main {
    private static int findFirst(int[] a, int key) {
        int l = 0, r = a.length - 1, ans = -1;
        while (l <= r) {
            int m = l + (r - l) / 2;
            if (a[m] < key) l = m + 1;
            else if (a[m] > key) r = m - 1;
            else { ans = m; r = m - 1; }
        }
        return ans;
    }
    private static int findLast(int[] a, int key) {
        int l = 0, r = a.length - 1, ans = -1;
        while (l <= r) {
            int m = l + (r - l) / 2;
            if (a[m] < key) l = m + 1;
            else if (a[m] > key) r = m - 1;
            else { ans = m; l = m + 1; }
        }
        return ans;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int key = Integer.parseInt(st.nextToken());
            int[] arr = new int[n];
            if (n > 0) {
                st = new StringTokenizer(br.readLine());
                for (int i = 0; i < n; ++i) arr[i] = Integer.parseInt(st.nextToken());
            } else {
                // consume the (empty) line if present
                br.readLine();
            }
            int first = findFirst(arr, key);
            int last = findLast(arr, key);
            sb.append(first).append(' ').append(last).append('\n');
        }
        System.out.print(sb.toString());
    }
}

