import sys

def find_first(arr, key):
    left, right = 0, len(arr) - 1
    ans = -1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] < key:
            left = mid + 1
        elif arr[mid] > key:
            right = mid - 1
        else:
            ans = mid
            right = mid - 1
    return ans

def find_last(arr, key):
    left, right = 0, len(arr) - 1
    ans = -1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] < key:
            left = mid + 1
        elif arr[mid] > key:
            right = mid - 1
        else:
            ans = mid
            left = mid + 1
    return ans

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        n_key = data[idx].split()
        idx += 1
        n = int(n_key[0])
        key = int(n_key[1])
        arr = []
        if n > 0:
            arr = list(map(int, data[idx].split()))
            idx += 1
        else:
            # skip the possibly empty line
            if idx < len(data) and data[idx] == '':
                idx += 1
        first = find_first(arr, key)
        last = find_last(arr, key)
        out.append(f"{first} {last}")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

